var TaniumPatchUtil = Class.create();
TaniumPatchUtil.prototype = Object.extendsObject(x_taniu_tan_core.TaniumIntegrationCore, {
	//x_taniu_tan_core.TaniumPatchUtil

	/**
	 * Get a page of patch definitions from the Tanium API Gateway.
	 *
	 * @param {Number} [overridePageSize=parseInt(gs.getProperty('x_taniu_tan_core.patch_definitions_page_size', '500'))] - The number of patch definitions to get per page. If not provided, the default page size
	 *    will be used, based on the x_taniu_tan_core.patch_definitions_page_size system property.
	 *    If that property is not set, the default page size will be 500.
	 *
	 * @param {Number} [overrideSkipCount=] - The number of patch definitions to skip when getting
	 *    the next page. If not provided, the skip count will be calculated based on the current
	 *    page number and page size.
	 *
	 * @returns {Object|null} - The response from the Tanium API Gateway, containing the patch
	 *    definitions for the page. If there are no more pages to get, null will be returned
	 *    instead.
	 *
	 * @throws {Error} - If the response body is invalid.
	 *
	 * @example
	 * function exampleGetPatchDefinitionsPage() {
	 * 	var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * 	var pageSize = 100; // Number of patch definitions to get per page
	 * 	var patchDefinitionsPage;
	 *
	 * 	// Loop until there are no more pages to retrieve
	 * 	while (patchUtil.patchDefinitionsHasNextPage()) {
	 * 		// Get the next page of patch definitions
	 * 		patchDefinitionsPage = patchUtil.getPatchDefinitionsPage(pageSize);
	 *
	 * 		// Print the page details
	 * 		gs.info(
	 * 			'Patch Definitions Page #' + patchUtil.getPatchDefinitionsPageNumber() + ': \n' +
	 * 			JSON.stringify(patchDefinitionsPage, null, 2)
	 * 		);
	 * 	}
	 *
	 * 	if (!patchUtil.patchDefinitionsHasNextPage()) {
	 * 		gs.info('No more pages of patch definitions to retrieve.');
	 * 	}
	 * }
	 */
	getPatchDefinitionsPage: function(overridePageSize, overrideSkipCount) {
		var rPatchDefinitions, responseBody, isLastPage;
		this._initPatchConfigIfEmpty();

		if (!this.patchDefinitionsHasNextPage()) {
			//If there are no more pages to get, return null
			return null;
		}

		rPatchDefinitions = this._getRESTObject( //Inherited from TaniumIntegrationCore
			'Patch - Tanium Integration Core',
			'Get Patch Definitions Page'
		);

		rPatchDefinitions.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT //Inherited from TaniumIntegrationCore
		);
		rPatchDefinitions.setStringParameter(
			'page_size',
			overridePageSize || this.patch_config.patch_definitions.page_size
		);
		rPatchDefinitions.setStringParameter(
			'skip_count',
			(gs.nil(overrideSkipCount) ? this._getPatchDefinitionsSkipValue() : overrideSkipCount)
		);

		responseBody = this._executeRESTCall(rPatchDefinitions); //From TaniumIntegrationCore
		if (
			!responseBody ||
			!responseBody.hasOwnProperty('total') ||
			!responseBody.hasOwnProperty('patches')
		) {
			//If the response body is invalid, throw an error
			throw new Error(
				'Invalid response body from Tanium API when getting patch definitions page:\n' +
				JSON.stringify(responseBody, null, 2)
			);
		}

		isLastPage = this._isLastPatchDefinitionPage(responseBody.total);
		//Update the patch config with the new page number and whether there are more pages to get
		this.patch_config.patch_definitions.has_next_page = !isLastPage;
		if (!isLastPage) {
			this.patch_config.patch_definitions.page++;
		}

		return responseBody;
	},

	/**
	 * Get a boolean indicating whether there are more pages of patch definitions to get.
	 *
	 * @returns {boolean} true if there are more pages of patch definitions to get, false otherwise.
	 *
	 * @example
	 * var patchResponse;
	 * var patch = new x_taniu_tan_core.TaniumPatchUtil();
	 *
	 * while (patch.patchDefinitionsHasNextPage()) {
	 *
	 *     patchResponse = patch.getPatchDefinitionsPage();
	 *     if (patchResponse) {
	 *         gs.info(
	 *             '\n\nCURRENT PAGE:\n' + JSON.stringify(patchResponse.patches, null, 2)
	 *         );
	 *     } else {
	 *         gs.error('This should not happen...');
	 *         break;
	 *     }
	 * }
	 */
	patchDefinitionsHasNextPage: function() {
		this._initPatchConfigIfEmpty();

		return this.patch_config.patch_definitions.has_next_page;
	},

	/**
	 * Get the current page number of patch definitions.
	 *
	 * @returns {number} - The current page number of patch definitions. If the first page has
	 *  not yet been retrieved, this will return 1.
	 *
	 *  This is different from the behavior of the .getPatchDefinitionsPageNumber() method,
	 *  which will return 0 if the first page has not yet been retrieved.
	 *
	 * @private
	 */
	_getPatchDefinitionsPageNumber: function() {
		this._initPatchConfigIfEmpty();

		return this.patch_config.patch_definitions.page;
	},

	/**
	 * Get the next page of all patch statuses for all endpoints.
	 *
	 * @param {Number} [pageSize=parseInt(gs.getProperty('x_taniu_tan_core.patch_status_page_size', '500'))]
	 *    - The number of patch statuses to get per page.
	 *
	 * @param {String} [startCursor=] - The cursor to start from when getting the next page of patch
	 *    statuses. If this argument is not specified, and if this is the first page of patch
	 *    statuses, the cursor will be null. If this argument is not provided, and we're NOT on the
	 *    first page of patch statuses, the cursor will be the cursor from the previous page (which
	 *    is stored in the patch config object in the instance of this class).
	 *
	 * @returns {{data}|boolean} - The response from the Tanium API Gateway, containing the patch
	 *    statuses for the page. Will return false if there are no more pages to get.
	 *
	 * @example
	 * function exampleGetNextPatchStatusPageAllEndpoints() {
	 * 	var patchStatusPage;
	 * 	var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * 	var pageSize = 500; // Number of patch statuses to get per page
	 *
	 * 	//Loop until the method returns a falsy value
	 * 	while (patchUtil.patchStatusHasNextPage()) {
	 * 		// Get the next page of patch statuses
	 * 		patchStatusPage = patchUtil.getNextPatchStatusPageAllEndpoints(pageSize);
	 *
	 * 		//Print the page details
	 * 		gs.info(
	 * 			'Patch Status Page: ' +
	 * 			JSON.stringify(
	 * 				patchStatusPage, null, 2
	 * 			)
	 * 		);
	 * 	}
	 *
	 * 	if (!patchUtil.patchStatusHasNextPage()) {
	 * 		gs.info('No more pages of patch statuses to retrieve.');
	 * 	}
	 * }
	 */
	getNextPatchStatusPageAllEndpoints: function(pageSize, startCursor) {
		//Get the patch status for all endpoints. This method will be used to refresh the patch statuses for all endpoints.
		var patchStatusResponse;
		this._initPatchConfigIfEmpty();

		//Override the page size if provided, after initializing the patch config
		if (pageSize) {
			this.patch_config.patch_status.page_size = pageSize;
		}

		//Override the cursor if provided. Otherwise, use the existing cursor from the patch config.
		if (startCursor) {
			this.patch_config.patch_status.cursor = startCursor;
		}

		if (!this.patchStatusHasNextPage()) {
			//If there are no more pages to get, return false
			return false;
		}

		//Get the next page of patch statuses for all endpoints
		patchStatusResponse = this._getPageAllPatchStatus();

		/*
								 ┓┏┏┓┓ ┳┳┓┏┓┏┳┓┏┓
								 ┃┃┣┫┃ ┃┃┃┣┫ ┃ ┣
								 ┗┛┛┗┗┛┻┻┛┛┗ ┻ ┗┛
		  ⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣀⣀⡠⠤⠤⣀⠀⠀⠀⠀⠀⠀⠀⣀⣀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠺⠯⣅⠀⠀⠀⠀⠀⢙⣆⣀⣀⣀⣴⠏⠁⣈⢳⡄⠀⠀⠀⠀⠀⠀⠀⠀⢀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⣳⡶⠒⠚⠉⠉⠉⠀⠀⠀⢿⣄⠀⠀⣰⡇⠀⠀⠀⠀⠀⠀⠀⠻⠿⢷⡄⠀
⠀⠀⠀⢠⣾⠶⣄⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢀⡴⠒⠺⢧⠀⠀⠀⠀⠀⢀⣀⣀⣀⠀⠙⠛⠋⠁⠙⣆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠹⡄
⢸⣟⠶⠛⠀⠐⢝⣳⡄⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠸⣜⠃⠀⣸⢀⣀⡤⢶⣫⣯⣷⣷⣾⣿⡄⠀⠀⠀⠀⢻⡄⠀⠀⠀⠀⠀⠀⠀⠀⣸⠃
⢸⡉⠀⠀⠀⠀⠀⠱⣝⣆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⢳⡚⢱⣫⣴⣿⣿⣿⣿⣿⣿⣿⣿⣿⡆⠀⠀⠀⠀⡇⠀⠀⠀⠀⠀⢀⣠⠞⠁⠀
⠈⢷⡀⠀⠀⠀⠀⠀⠀⠸⡆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⣧⠈⠙⠿⣿⣿⣿⣿⣿⣿⣿⣿⣿⣧⠀⠀⠀⢰⣷⠤⠤⠴⠒⠚⠉⠀⠀⠀⠀
⠀⠈⢷⡀⠀⠀⠀⠀⠀⠠⣹⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠙⣆⠀⠀⠈⢻⣿⣿⣿⣿⣿⣿⣿⣿⠀⠀⠀⣼⢿⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠓⠧⠤⠤⣤⣤⢶⡅⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣸⣧⠀⠀⠸⢿⣿⣿⣿⣿⢛⡽⠋⠀⠀⣰⠃⠀⣧⠀⠀⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠹⣆⠹⣆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢀⣠⠞⠁⠘⣦⠀⠀⠀⠀⠉⠉⠉⠉⠀⠀⠀⢰⠇⠀⠀⢹⡄⠀⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠘⢦⡙⢧⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣠⡴⠛⠁⠀⠀⠀⠉⢷⣄⡀⠀⠀⠀⠀⠀⣀⡤⠶⠋⠀⠀⠀⠀⢧⠀⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⠳⡄⢹⣄⠀⠀⠀⠀⠀⠀⠀⢀⣠⡴⠚⠁⠀⠀⠀⠀⠀⠀⠀⠈⣆⠉⠉⠉⠉⠉⠉⠉⠀⠀⠀⠀⠀⠀⢸⡄⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠙⣦⠹⣦⠀⠀⢀⣠⡴⠞⠋⠁⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠘⡆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⣧⠀⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⢷⡿⢷⡚⠉⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢹⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢸⡄⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠹⣄⠹⣆⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⡇⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢠⡇⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠘⢧⡘⢧⡀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⡇⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠘⡇⠀⠀⠀⠀⠀⠀
⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠈⠷⣄⣷⣄⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⢰⠇⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⠀⡇⠀⠀⠀⠀⠀⠀
							┏┓┓ ┓   ┏┳┓┓┏┏┓  ┏┳┓┓┏┳┳┓┏┓┏┓
							┣┫┃ ┃    ┃ ┣┫┣    ┃ ┣┫┃┃┃┃┓┗┓
							┛┗┗┛┗┛   ┻ ┛┗┗┛   ┻ ┛┗┻┛┗┗┛┗┛
		 */
		if (
			//Validate response exists and has data
			!patchStatusResponse ||
			!patchStatusResponse.hasOwnProperty('data') ||
			!patchStatusResponse.data ||
			//Validate endpoint data exists and has records
			!patchStatusResponse.data.hasOwnProperty('endpoints') ||
			!patchStatusResponse.data.endpoints ||
			!patchStatusResponse.data.endpoints.hasOwnProperty('edges') ||
			!patchStatusResponse.data.endpoints.edges ||
			patchStatusResponse.data.endpoints.edges.length < 1 ||
			//Validate page info exists
			!patchStatusResponse.data.endpoints.hasOwnProperty('pageInfo') ||
			!patchStatusResponse.data.endpoints.pageInfo ||
			!patchStatusResponse.data.endpoints.pageInfo.hasOwnProperty('hasNextPage') ||
			!patchStatusResponse.data.endpoints.pageInfo.hasOwnProperty('endCursor') ||
			//Validate the first endpoint node exists
			!patchStatusResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!patchStatusResponse.data.endpoints.edges[0].node
		) {
			gs.debug(
				'Invalid response from Tanium API when getting patch statuses for all endpoints:\n' +
				JSON.stringify(patchStatusResponse, null, 2) + '\n' +
				'Here\'s the patch config:\n' +
				JSON.stringify(this.patch_config, null, 2)
			);
			//Set the has next page flag to false, since we don't want to keep trying to get more pages if the response is invalid. Then, return false. We don't want to throw an error here, since we don't want to halt the script if the response is invalid.
			this.patch_config.patch_status.has_next_page = false;
			return false;
		}

		//Update the patch config with the new cursor and whether there are more pages to get
		this.patch_config.patch_status.cursor = patchStatusResponse.data.endpoints.pageInfo.endCursor;
		this.patch_config.patch_status.has_next_page = patchStatusResponse.data.endpoints.pageInfo.hasNextPage;

		return patchStatusResponse;
	},

	/**
	 * Get the current page number of patch statuses.
	 *
	 * @returns {number} - The current page number of patch statuses, or 0 if the
	 *  first page has not yet been retrieved.
	 *
	 * @example
	 * function exampleGetNextPatchStatusPageAllEndpoints() {
	 * 	var patchStatusPage;
	 * 	var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * 	var pageSize = 100; // Number of patch statuses to get per page
	 *
	 * 	//Loop until the method returns a falsy value
	 * 	while (patchUtil.patchStatusHasNextPage()) {
	 * 		// Get the next page of patch statuses
	 * 		patchStatusPage = patchUtil.getNextPatchStatusPageAllEndpoints(pageSize);
	 *
	 * 		//Print the page details
	 * 		gs.info(
	 * 			'Patch Status Page #' + patchUtil.getPatchStatusPageNumber() + ': \n' +
	 * 			JSON.stringify(
	 * 				patchStatusPage, null, 2
	 * 			)
	 * 		);
	 * 	}
	 *
	 * 	if (!patchUtil.patchStatusHasNextPage()) {
	 * 		gs.info('No more pages of patch statuses to retrieve.');
	 * 	}
	 * }
	 */
	getPatchStatusPageNumber: function() {
		this._initPatchConfigIfEmpty();

		return this.patch_config.patch_status.page;
	},

	/**
	 * Get whether there are more pages of patch statuses to get for all endpoints.
	 * If no patch statuses have been retrieved yet, this method will return true, since we assume
	 * there are more pages to get until we get at least the first page.
	 *
	 * @returns {boolean} - True if there are more pages of patch statuses to get, false otherwise.
	 *
	 * @example
	 * function exampleGetNextPatchStatusPageAllEndpoints() {
	 * 	var patchStatusPage;
	 * 	var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * 	var pageSize = 500; // Number of patch statuses to get per page
	 *
	 * 	//Loop until the method returns a falsy value
	 * 	while (patchUtil.patchStatusHasNextPage()) {
	 * 		// Get the next page of patch statuses
	 * 		patchStatusPage = patchUtil.getNextPatchStatusPageAllEndpoints(pageSize);
	 *
	 * 		//Print the page details
	 * 		gs.info(
	 * 			'Patch Status Page: ' +
	 * 			JSON.stringify(
	 * 				patchStatusPage, null, 2
	 * 			)
	 * 		);
	 * 	}
	 *
	 * 	if (!patchUtil.patchStatusHasNextPage()) {
	 * 		gs.info('No more pages of patch statuses to retrieve.');
	 * 	}
	 * }
	 */
	patchStatusHasNextPage: function() {
		this._initPatchConfigIfEmpty();

		return this.patch_config.patch_status.has_next_page;
	},

	/**
	 * Get the patch status for a single endpoint. This method will be used in the event that we
	 *  have a single endpoint for which we want to get the patch statuses specifically, rather
	 *  than getting the patch statuses for all endpoints (using
	 *  .getNextPatchStatusPageAllEndpoints()).
	 *
	 * @param {String} [fqdn=] - The fully qualified domain name of the endpoint.
	 *
	 * @param {String} [serialNumber=] - The serial number of the endpoint.
	 *
	 * @param {String} [taniumEndpointID=] - The Tanium endpoint ID of the endpoint. If this is
	 *   provided, the fqdn and serialNumber parameters will be ignored, as Endpoint ID is the
	 *   most authoritative way to identify an endpoint.
	 *
	 *  You can get the endpoint ID by calling the getEndpointID() method, which is part of the
	 *   TaniumIntegrationCore class. Since the TaniumPatchUtil class extends TaniuIntegrationCore,
	 *   you can call this method directly on an instance of TaniumPatchUtil.
	 *
	 * @param {Boolean} [warnIfMultipleEndpointsFound=true] - If true, a warning will be logged if
	 *    multiple endpoints are found when getting the patch status for the endpoint. If false, no
	 *    warning will be logged in this event. Either way, the first endpoint found will be used to
	 *    get the patch status.
	 *
	 * @returns {Object} - The response from the Tanium API Gateway, containing the patch status for
	 *    the endpoint. This response will be in the format of the response from the "Patch - Patch
	 *    List Applicability Results" sensor, along with some additional endpoint information.
	 *
	 *    Will return false if the endpoint wasn't found.
	 *
	 * @example
	 * function exampleGetPatchStatusForEndpoint() {
	 * 	var patchStatus;
	 * 	var fqdn = 'endpoint1.example.com';
	 * 	var serialNumber = '12345';
	 * 	var taniumEndpointID = '67890';
	 * 	var warnIfMultipleEndpointsFound = true;
	 * 	var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 *
	 * 	patchStatus = patchUtil.getPatchStatusForEndpoint(
	 * 		fqdn,
	 * 		serialNumber,
	 * 		taniumEndpointID,
	 * 		warnIfMultipleEndpointsFound
	 * 	);
	 *
	 * 	if (patchStatus) {
	 * 		gs.info('Patch Status: ' + JSON.stringify(patchStatus, null, 2));
	 * 	} else {
	 * 		gs.error('No patch status found for the specified endpoint.');
	 * 	}
	 * }
	 */
	getPatchStatusForEndpoint: function(fqdn, serialNumber, taniumEndpointID, warnIfMultipleEndpointsFound) {
		this._initPatchConfigIfEmpty();
		var patchStatusResponse;

		//Default to true if not explicitly set to false.
		warnIfMultipleEndpointsFound = (warnIfMultipleEndpointsFound !== false);

		//Validate inputs
		if (!fqdn && !serialNumber && !taniumEndpointID) {
			throw new Error(
				'At least one of the following parameters must be provided when calling ' +
				'TaniumPatchUtil.getPatchStatusForEndpoint(): \n' +
				'fqdn, serialNumber, taniumEndpointID \n' +
				'(the first, second, and third parameters respectively).'
			);
		}

		patchStatusResponse = this._getSingleEndpointPatchStatuses(
			fqdn,
			serialNumber,
			taniumEndpointID
		);

		if (!patchStatusResponse) {
			return false;
		}

		//Check if multiple endpoints were found, or if there's a second page of results
		if (
			warnIfMultipleEndpointsFound &&
			(
				patchStatusResponse.data.endpoints.contributedTotal > 1 ||
				patchStatusResponse.data.endpoints.pageInfo.hasNextPage === true ||
				patchStatusResponse.data.endpoints.edges.length > 1
			)
		) {
			gs.warn(
				'Multiple endpoints found when getting patch status for endpoint ' +
				'with FQDN "' + fqdn + '", serial number "' + serialNumber +
				'", and Tanium endpoint ID "' + taniumEndpointID + '". That\'s probably ' +
				'not good, since we only expect one endpoint to match the given ' +
				'criteria when this method is called.\n' +
				'Here\'s the response:\n' +
				JSON.stringify(patchStatusResponse, null, 2)
			);
		}

		return patchStatusResponse;
	},

	/**
	 * Trigger a Tanium Patch Deployment for a set of patches to a set of endpoints matching a
	 * specific operating system type (Windows or Linux).
	 *
	 * Be sure to note the default behavior of each non-mandatory parameter - especially
	 * overrideMaintWindow and overrideBlocklist - and be sure to specify values for those arguments
	 * if you wish to override the default behavior.
	 *
	 * @param {String} name - The name of the patch deployment. This can be anything you want, but
	 *    should be descriptive.
	 *
	 * @param {String} description - A description of the patch deployment. This can be anything you
	 *    want, but should be descriptive.
	 *
	 * @param {"WINDOWS"|"LINUX"} osType - The operating system type for the patch deployment. This
	 *    should be either "WINDOWS" or "LINUX".
	 *
	 * @param {"INSTALL"|"UNINSTALL"} [operation="INSTALL"] - The operation to perform with the
	 *    patches. This should be either "INSTALL" or "UNINSTALL". If not specified (or set to
	 *    null), the default value is "INSTALL".
	 *
	 * @param {Array<{fqdn: string, serial_number: string}>} targetEndpoints - An array of objects,
	 *    each containing the FQDN and/or serial number of an endpoint to which to deploy the
	 *    patches.
	 *
	 * @param {Array<String>} [patchUIDs=[]] - An array of Tanium patch UIDs as strings. At least
	 *   one of this or patchLists must be provided (If this is not specified, then patchLists must
	 *   be).
	 *
	 *  To skip this parameter, simply set it to null.
	 *
	 *  upcoming_feature: Check what happens when both this and patchLists are passed to the
	 *    API... do we need ot ensure that ONLY one is specified? I assume not since it allows
	 *    that on the front-end in the Tanium console but let's make sure that the API accepts
	 *    both (or either).
	 *    Also, what happens if neither are specified?
	 *
	 * @param {Array<{id: string, version: string}>} [patchLists=[]] - An array of Patch List
	 *  objects. Each Patch List object must contain an ID, and may optionally contain a version.
	 *  If a version is not provided, the latest version of the patch list will be used. At least
	 *  one of this or patchUIDs must be provided.
	 *
	 *  To skip this parameter, simply set it to null.
	 *
	 *  upcoming_feature: Default to LATEST version, or pinned version?
	 *
	 *  NOTE: Using patch lists is still experimental. This should be functional, but should be
	 *   tested before use in production.
	 *
	 * @param {Number} msStartTime - The start time for the patch deployment, in milliseconds since
	 *  the epoch.
	 *
	 * @param {Number} msEndTime - The end time for the patch deployment, in milliseconds since the
	 *  epoch.
	 *
	 *  upcoming_feature: Should we have default values for these? If so, what should they be? I
	 *    could default start time to now, and end time to... 24 hours from now? Or, what should be
	 *    the default duration if not specified? Also, if msStartTime is specified but msEndTime is
	 *    not, I can default msEndTime to some specific number of ms after msStartTime - just need
	 *    to know what the default duration should be between them.
	 *
	 * @param {boolean} [overrideMaintWindow=true] - Whether to override the maintenance window for
	 *   the patch deployment. If true, the patch deployment may be performed outside of the
	 *   maintenance window. If false, the patch deployment will only be deployed during the
	 *   default maintenance window defined in the Tanium Patch module. Default value is true.
	 *
	 * @param {boolean} [overrideBlocklist=true] - Whether to override the blocklist for the patch
	 *   deployment. If true, blocklists defined in Tanium Patch will not be considered for this
	 *   deployment. Default value is true because we assume that if you're deploying specific
	 *   patches to specific endpoints, you want to deploy them regardless of any blocklists.
	 *
	 * @param {"ON_INSTALL"|"ON_REQUIRED"|"NEVER"} [restartBehavior="NEVER"] - The restart behavior
	 *   for the patch deployment. This should be one of "ON_INSTALL", "ON_REQUIRED", or "NEVER".
	 *   Default value is "NEVER".
	 *
	 * @returns {{id: number}} - The response from the Tanium API, containing the details of the
	 *   patch deployment.
	 *
	 * @example
	 * var deploymentResponse;
	 * var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * var gdtStartTime = new GlideDateTime();
	 * var gdtEndTime = new GlideDateTime();
	 * var patchUIDs = ['patch1', 'patch2'];
	 * var targetEndpoints = [
	 * 	{ fqdn: 'endpoint1.example.com', serial_number: '12345' },
	 * 	{ fqdn: 'endpoint2.example.com', serial_number: '67890' }
	 * ];
	 *
	 * gdtStartTime.add(86400000); // 24 hours from now
	 * gdtEndTime.add(172800000); // 48 hours from now
	 *
	 * deploymentResponse = patchUtil.deployPatchesToEndpoints(
	 * 	'Monthly Security Patches',
	 * 	'Deploying critical security patches to all endpoints',
	 * 	'WINDOWS',
	 * 	'INSTALL',
	 * 	targetEndpoints,
	 * 	patchUIDs,
	 * 	null,
	 * 	gdtStartTime.getNumericValue(),
	 * 	gdtEndTime.getNumericValue(),
	 * 	true, // Override maintenance window
	 * 	true, // Override blocklist
	 * 	'NEVER' // Restart behavior
	 * );
	 * //...
	 */
	deployPatchesToEndpoints: function(
		name,
		description,
		osType,
		operation,
		targetEndpoints,
		patchUIDs,
		patchLists,
		msStartTime,
		msEndTime,
		overrideMaintWindow,
		overrideBlocklist,
		restartBehavior
	) {
		/* Example payload being constructed:
		{
			"name": "${patch_deployment_name}",
			"description": "${patch_deployment_description}",
			"osType": "${os_type}",
			"patchOperation": "${patch_operation}",
			"targetEndpoints": ${target_endpoints}, //array of endpoint objects (each with a "fqdn" and/or "serial_number" field)
			"patchTaniumUids": ${patch_uids}, //array of Tanium patch UIDs as strings
			"patchLists": ${patch_lists}, //array of patch list objects
			"schedule": {
				"startTime": "${start_time_ms}",
				"endTime": "${end_time_ms}",
				"overrideWindow": ${override_maint_window} //boolean
			},
			"overrideBlockList": ${override_block_list}, //boolean
			"restartBehavior": "${restart_behavior}",
		}
		*/

		var rDeployPatches, createDeploymentResponse;

		//Set default input values
		operation = (operation && typeof operation === 'string') ? operation : 'INSTALL';
		overrideMaintWindow = (typeof overrideMaintWindow === 'boolean') ? overrideMaintWindow : true;
		overrideBlocklist = (typeof overrideBlocklist === 'boolean') ? overrideBlocklist : true;
		restartBehavior = (restartBehavior && typeof restartBehavior === 'string') ? restartBehavior : 'NEVER';
		description = (description) ? description : name; //If no description is provided, default to the name.
		patchLists = (typeof patchLists === 'undefined') ? [] : patchLists;
		patchUIDs = (typeof patchUIDs === 'undefined') ? [] : patchUIDs;

		//Validate inputs
		if (//Mandatory values which must be truthy.
			(!name || !(typeof name == 'string')) ||
			(!description || !(typeof description == 'string')) ||
			(!osType || (['windows', 'linux'].indexOf(osType.toLowerCase()) === -1)) ||
			(!operation || (['install', 'uninstall'].indexOf(operation.toLowerCase()) === -1)) ||
			(!targetEndpoints || !Array.isArray(targetEndpoints) || targetEndpoints.length < 1) ||
			!msStartTime || !(typeof msStartTime == 'number') ||
			!msEndTime || !(typeof msEndTime == 'number') ||
			//At least one of these must be truthy and a valid array.
			(
				!patchUIDs || !Array.isArray(patchUIDs) || patchUIDs.length < 1
			) &&
			(
				!patchLists || !Array.isArray(patchLists) || patchLists.length < 1
			) ||
			!restartBehavior || (['ON_INSTALL', 'ON_REQUIRED', 'NEVER'].indexOf(restartBehavior) === -1)
		) {
			throw new Error(
				'Invalid parameter(s) provided to TaniumPatchUtil.deployPatchesToEndpoints():\n' +
				'name: ' + name + ' (mandatory, string)\n' +
				'description: ' + description + '\n' +
				'osType: ' + osType + ' (mandatory enum string, WINDOWS|LINUX)\n' +
				'targetEndpoints: ' + JSON.stringify(targetEndpoints, null, 2) + '\n' +
				'msStartTime: ' + msStartTime + '\n' +
				'msEndTime: ' + msEndTime + '\n' +
				'patchUIDs: ' + JSON.stringify(patchUIDs, null, 2) + '\n' +
				'patchLists: ' + JSON.stringify(patchLists, null, 2) + '\n' +
				'(At least one of patchUIDs or patchLists must be provided.)' +
				'restartBehavior: ' + restartBehavior + ' (enum string, ON_INSTALL|ON_REQUIRED|NEVER)' +
				'operation: ' + operation + ' (enum string, INSTALL|UNINSTALL)' +
				'overrideMaintWindow: ' + overrideMaintWindow + ' (boolean)' +
				'overrideBlocklist: ' + overrideBlocklist + ' (boolean)'
			);
		}

		this._initPatchConfigIfEmpty();

		/* Example payload being constructed:
		{
			"name": "${patch_deployment_name}",
			"description": "${patch_deployment_description}",
			"osType": "${os_type}",
			"patchOperation": "${patch_operation}",
			"targetEndpoints": ${target_endpoints}, //array of endpoint objects (each with a "fqdn" and/or "serial_number" field)
			"patchTaniumUids": ${patch_uids}, //array of Tanium patch UIDs as strings
			"patchLists": ${patch_lists}, //array of patch list objects
			"schedule": {
				"startTime": "${start_time_ms}",
				"endTime": "${end_time_ms}",
				"overrideWindow": ${override_maint_window} //boolean
			},
			"overrideBlockList": ${override_block_list}, //boolean
			"restartBehavior": "${restart_behavior}",
		}
		*/
		//Construct the deployment request and body.
		rDeployPatches = this._getRESTObject(
			'Patch - Tanium Integration Core',
			'Create Patch Deployment'
		);

		rDeployPatches.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT
		);

		rDeployPatches.setStringParameterNoEscape(
			'patch_deployment_name',
			name
		);
		rDeployPatches.setStringParameterNoEscape(
			'patch_deployment_description',
			description
		);
		rDeployPatches.setStringParameterNoEscape(
			'os_type',
			osType.toUpperCase()
		);
		rDeployPatches.setStringParameterNoEscape(
			'patch_operation',
			operation.toUpperCase()
		);
		rDeployPatches.setStringParameterNoEscape(
			'start_time_ms',
			msStartTime
		);
		rDeployPatches.setStringParameterNoEscape(
			'end_time_ms',
			msEndTime
		);
		rDeployPatches.setStringParameterNoEscape(
			'override_maint_window',
			overrideMaintWindow
		);
		rDeployPatches.setStringParameterNoEscape(
			'override_block_list',
			overrideBlocklist
		);
		rDeployPatches.setStringParameterNoEscape(
			'restart_behavior',
			restartBehavior
		);
		rDeployPatches.setStringParameterNoEscape(
			'patch_uids',
			JSON.stringify(patchUIDs)
		);
		rDeployPatches.setStringParameterNoEscape(
			'patch_lists',
			JSON.stringify(patchLists)
		);
		rDeployPatches.setStringParameterNoEscape(
			'target_endpoints',
			JSON.stringify(targetEndpoints)
		);

		//Execute the deployment request
		createDeploymentResponse = this._executeRESTCall( //inherited from x_taniu_tan_core.TaniumIntegrationCore
			rDeployPatches,
			false,
			true,
			false,
			true
		);

		return createDeploymentResponse;
	},

	/**
	 * Get the details of a specific patch deployment.
	 *
	 * @param {String|Number} patchDeploymentID - The ID of the patch deployment for which to
	 *  retrieve the details.
	 *
	 * @returns {Object|Boolean} - The response from the Tanium API, containing the details of
	 *  the patch deployment. Will return false if the patch deployment wasn't found.
	 *
	 * @throws {Error} - If no patch deployment ID is provided.
	 *
	 * @example
	 * var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * var deploymentDetails = patchUtil.getPatchDeploymentDetails(12345);
	 * gs.info('Patch Deployment Details: ' + JSON.stringify(deploymentDetails, null, 2));
	 */
	getPatchDeploymentDetails: function(patchDeploymentID) {
		var rPatchDeployment, responseBody, isActive, isEnded;
		this._initPatchConfigIfEmpty();

		if (!patchDeploymentID) {
			//If deployment ID not provided, throw an error
			throw new Error(
				'No patch deployment ID provided to TaniumPatchUtil.getPatchDeploymentDetails().'
			);
		}

		rPatchDeployment = this._getRESTObject( //Inherited from TaniumIntegrationCore
			'Patch - Tanium Integration Core',
			'Get Patch Deployment Details'
		);

		rPatchDeployment.setStringParameterNoEscape(
			'tanium_module_api_url',
			this.TANIUM_MODULE_API_ENDPOINT //Inherited from TaniumIntegrationCore
		);
		rPatchDeployment.setStringParameter(
			'patch_deployment_id',
			patchDeploymentID
		);

		responseBody = this._executeRESTCall( //From TaniumIntegrationCore
			rPatchDeployment,
			true,
			true,
			false,
			true
		);

		return responseBody;
	},

	/**
	 * Check if a specific patch deployment is completed.
	 * This method will return true if the patch deployment is completed, and false if it is not.
	 * If the patch deployment is ended, or if it is no longer active, then it is considered
	 *  completed, so this method will return true in those cases.
	 *
	 * @param {String|Number} patchDeploymentID - The ID of the patch deployment to check.
	 *
	 * @returns {Boolean} - True if the patch deployment is completed, false otherwise.
	 *
	 * @throws {Error} - If the response body from the Tanium API is invalid.
	 *
	 * @example
	 * var patchUtil = new x_taniu_tan_core.TaniumPatchUtil();
	 * var isCompleted = patchUtil.isPatchDeploymentCompleted('12345');
	 * gs.info('Is Patch Deployment Completed: ' + isCompleted);
	 */
	isPatchDeploymentCompleted: function(patchDeploymentID) {
		var responseBody, isEnded, isActive;

		responseBody = this.getPatchDeploymentDetails(patchDeploymentID);

		if (
			!responseBody ||
			!responseBody.hasOwnProperty('isActive') ||
			!responseBody.hasOwnProperty('isEnded')
		) {
			//If the response body is invalid, throw an error
			throw new Error(
				'Invalid response body from Tanium API when getting patch deployment status:\n' +
				JSON.stringify(responseBody, null, 2)
			);
		}

		isEnded = !!responseBody.isEnded;
		isActive = !!responseBody.isActive;

		//If the patch deployment has ended, return true.
		//If it hasn't ended, then return true (the deployment is completed) only if it's no longer active. If it's still active, return false.
		return isEnded || !isActive;
	},

