	/****************************/
	/***HELPER FUNCTIONS BELOW***/
	/****************************/

	/**
	 * Filter a list of deployment templates by a key and value. This method is used to filter the
	 * list of deployment templates returned by the Tanium API, specifically as turned from the
	 * .getAllDeployTemplates() method.
	 *
	 * Passing in a key (such as "osType") and a value (such as "windows") will create a new array
	 * (leaving the original array unmodified) and populate it with only the deployment templates
	 * that have an "osType" key with a value of "windows". This new array will then be returned.
	 *
	 * @param {[{createdAt: string, osType: string, deploymentTemplateId: number, type: string,
	 *    updatedAt: string}]} deploymentTemplateList - The list of deployment templates to filter
	 *    out. This list should be in the format returned by the Tanium API, specifically as
	 *    returned from the .getAllDeployTemplates() method, at the location $.deploymentTemplates.
	 * @param {string} filterOnKey - The key to filter on. This should be a key that exists in the
	 *    deployment template objects in the deploymentTemplateList array. Note that this key should
	 *    be a string, but may contain a dot-walked path. For example, "contentSet.contentSetId"
	 *    would be a valid key to filter on. This would filter the deployment templates by the
	 *    content set ID.
	 * @param {string|number|boolean} filterMatchValue - The value to match on the key. If the key
	 *    is a dot-walked path, this value should be the value at the end of the path. Only
	 *    primitive values are supported for the filterMatchValue, as objects and arrays are never
	 *    equal to each other (even when identical) on account of the way JavaScript handles object
	 *    and array variables (by reference).
	 *
	 * @private
	 */
	_filterDeploymentTemplateList: function(deploymentTemplateList, filterOnKey, filterMatchValue) {
		var iTemplate, template;
		var filteredTemplates = [];

		//Validate inputs
		if (
			!deploymentTemplateList ||
			!filterOnKey ||
			!filterMatchValue ||
			typeof filterOnKey !== 'string'
		) {
			throw new Error(
				'Invalid parameters provided to TaniumPatchUtil._filterDeploymentTemplateList():\n' +
				'deploymentTemplateList: ' + JSON.stringify(deploymentTemplateList, null, 2) + '\n' +
				'filterOnKey: ' + filterOnKey + '\n' +
				'filterMatchValue: ' + filterMatchValue
			);
		}

		for (iTemplate = 0; iTemplate < deploymentTemplateList.length; iTemplate++) {
			template = deploymentTemplateList[iTemplate];
			if (!template || !template.hasOwnProperty(filterOnKey)) {
				gs.warn(
					'Key ' + filterOnKey + ' not found in deployment template object ' +
					'at index ' + iTemplate + ' in the deployment template list:\n' +
					JSON.stringify(template, null, 2)
				);
				continue; //Skip this template if the key doesn't exist.
			}

			if (template[filterOnKey] == filterMatchValue) {
				filteredTemplates.push(template);
			} else if (filterOnKey.includes('.')) {
				//If the key is a dot-walked path, try to get the value from the dot-walked path
				if (this._getDotWalkedPropertyValue(template, filterOnKey) === filterMatchValue) {
					filteredTemplates.push(template);
				}
			}
		}

		return filteredTemplates;
	},

	_getDotWalkedPropertyValue: function(obj, dotWalkedPath) {
		var iPath, pathParts, pathPart, value;

		if (!obj || !dotWalkedPath) {
			gs.warn(
				'Invalid parameters provided to TaniumPatchUtil._getDotWalkedPropertyValue():\n' +
				'obj: ' + JSON.stringify(obj, null, 2) + '\n' +
				'dotWalkedPath: ' + dotWalkedPath
			);
			return null;
		}

		pathParts = dotWalkedPath.split('.');
		value = obj;

		for (iPath = 0; iPath < pathParts.length; iPath++) {
			pathPart = pathParts[iPath];
			if (!value || !value.hasOwnProperty(pathPart)) {
				//If the value doesn't exist or doesn't have the property, return null
				return null;
			}
			value = value[pathPart];
		}

		return value;
	},


	_getEndpointBySerialOrFQDN: function(fqdn, serialNumber) {
		var gqMatch;
		var grEndpoint = new GlideRecord('cmdb_ci');
		//"Serial Number"|"FQDN"|"FQDN and Serial"|"Serial or FQDN"
		var identifyCIBySerial = gs.getProperty(
			'x_taniu_tan_core.patch_match_ci_by_field',
			'Serial or FQDN'
		);
		var allowNameAsFQDN = gs.getProperty(
			'x_taniu_tan_core.patch_allow_name_as_fqdn',
			'true'
		) === 'true';

		if (!fqdn && !serialNumber) {
			throw new Error(
				'At least one (preferably both) of the following parameters must be provided when calling ' +
				'TaniumPatchUtil._getEndpointBySerialOrFQDN(): \n' +
				'fqdn, serialNumber \n' +
				'(the first and second parameters respectively).'
			);
		}

		//Add the query conditions based on the .patch_match_ci_by_field property.
		if (identifyCIBySerial === 'Serial Number') {
			grEndpoint.addQuery('serial_number', serialNumber);
		} else if (identifyCIBySerial === 'FQDN') {
			gqMatch = grEndpoint.addQuery('fqdn', fqdn);
			if (allowNameAsFQDN) {
				gqMatch.addOrCondition('name', fqdn);
			}
		} else if (identifyCIBySerial === 'FQDN and Serial') {
			grEndpoint.addQuery('serial_number', serialNumber);

			gqMatch = grEndpoint.addQuery('fqdn', fqdn);
			if (allowNameAsFQDN) {
				gqMatch.addOrCondition('name', fqdn);
			}
		} else if (identifyCIBySerial === 'Serial or FQDN') {
			gqMatch = grEndpoint.addQuery('serial_number', serialNumber)
				.addOrCondition('fqdn', fqdn);

			if (allowNameAsFQDN) {
				gqMatch.addOrCondition('name', fqdn);
			}
		}

		//upcoming_feature: This is a naive match where if we're using "serial or FQDN" we just return the first endpoint that's found. We're doing this intentionally for performance reasons, but in the future we may consider sacrificing a bit of performance in exchange for more accurate results.
		// More accurate results could be achieved by removing the limit and then checking if any endpoints match both serial and FQDN, and if so, return that endpoint. If not, then return the first endpoint that matches either serial or FQDN.
		grEndpoint.setLimit(1); //Only get one record, if any.
		grEndpoint.query();

		return grEndpoint.next() ? grEndpoint : false;
	},

	/**
	 * Get an object with patch UIDs as keys and install statuses as values - representing a single
	 * endpoint's patch statuses.
	 * @param patchStatusObj
	 * @returns {{}}
	 * @private
	 */
	_getEndpointPatchStatuses: function(patchStatusObj) {
		var iPatch, patchUIDs, installStatuses;
		var patchStatuses = {};

		if (
			!patchStatusObj ||
			!patchStatusObj.hasOwnProperty('sensorReadings') ||
			!patchStatusObj.sensorReadings ||
			!patchStatusObj.sensorReadings.hasOwnProperty('columns') ||
			!patchStatusObj.sensorReadings.columns ||
			patchStatusObj.sensorReadings.columns.length < 1
		) {
			throw new Error(
				'Invalid patch status object provided to TaniumPatchUtil._getEndpointPatchStatuses():\n' +
				JSON.stringify(patchStatusObj, null, 2)
			);
		}

		//Get the Tanium UIDs and install statuses from the sensor readings
		patchUIDs = this._getSensorReadingValuesByName(
			patchStatusObj.sensorReadings,
			'Tanium UID'
		);
		installStatuses = this._getSensorReadingValuesByName(
			patchStatusObj.sensorReadings,
			'Install Status'
		);

		//Validate the patch UIDs and install statuses
		if (
			!patchUIDs ||
			!installStatuses ||
			patchUIDs.length < 1 ||
			installStatuses.length < 1 ||
			patchUIDs.length !== installStatuses.length
		) {
			throw new Error(
				'Invalid patch UIDs and/or install statuses provided to TaniumPatchUtil._getEndpointPatchStatuses():\n' +
				'patchUIDs: ' + JSON.stringify(patchUIDs, null, 2) + '\n' +
				'installStatuses: ' + JSON.stringify(installStatuses, null, 2)
			);
		}

		//Create an object with the patch UIDs as keys and the install statuses as values
		//iPatch is the index of the patch UID and install status in the arrays
		// (the sub-rows returned from the sensor readings)
		for (iPatch = 0; iPatch < patchUIDs.length; iPatch++) {
			patchStatuses[patchUIDs[iPatch]] = installStatuses[iPatch];
		}

		return patchStatuses;
	},

	_getSensorReadingValuesByName: function(sensorReadings, columnName) {
		//Get the values of a sensor reading column by name.
		var iCol, column;
		var columnValues = null;

		if (
			!sensorReadings ||
			!sensorReadings.hasOwnProperty('columns') ||
			!sensorReadings.columns ||
			sensorReadings.columns.length < 1
		) {
			throw new Error(
				'Invalid sensor readings object provided to TaniumPatchUtil._getSensorReadingValuesByName():\n' +
				JSON.stringify(sensorReadings, null, 2)
			);
		}

		for (iCol = 0; iCol < sensorReadings.columns.length; iCol++) {
			column = sensorReadings.columns[iCol];
			if (column.name === columnName) {
				columnValues = column.values;
				break;
			}
		}

		return columnValues;

	},

	_getPageAllPatchStatus: function() {
		this._initPatchConfigIfEmpty();
		var patchStatusResponse;
		var gqUtil = new x_taniu_tan_core.GatewayQueryUtil();

		//Validate inputs
		/* if (!fqdn && !serialNumber && !taniumEndpointID) {
			throw new Error(
				'At least one of the following parameters must be provided when calling ' +
				'TaniumPatchUtil.getPatchStatusForEndpoint(): \n' +
				'fqdn, serialNumber, taniumEndpointID \n' +
				'(the first, second, and third parameters respectively).'
			);
		} */

		gqUtil.useCachedData();

		gqUtil.addSensor('Computer Name');
		gqUtil.addSensor('Computer Serial Number');
		gqUtil.addSensor('OS Platform');

		gqUtil.addSensor('Patch - Patch List Applicability Results')
			.addColumn('Tanium UID')
			.addColumn('Install Status');

		if (this.patch_config.patch_status.page_size) {
			gqUtil.setPageSize(this.patch_config.patch_status.page_size);
		}

		if (this.patch_config.patch_status.cursor) {
			gqUtil.setCursor(this.patch_config.patch_status.cursor);
		}

		patchStatusResponse = gqUtil.getNextPage();

		//Validate response. If no endpoints were found, throw an error.
		if (
			!patchStatusResponse ||
			!patchStatusResponse.hasOwnProperty('data') ||
			!patchStatusResponse.data ||
			!patchStatusResponse.data.hasOwnProperty('endpoints') ||
			!patchStatusResponse.data.endpoints ||
			!patchStatusResponse.data.endpoints.hasOwnProperty('edges') ||
			!patchStatusResponse.data.endpoints.edges ||
			patchStatusResponse.data.endpoints.edges.length < 1 ||
			!patchStatusResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!patchStatusResponse.data.endpoints.edges[0].node
		) {
			gs.warn(
				'TaniumPatchUtil: No endpoints found when getting patch status for endpoint ' +
				'with FQDN "' + fqdn + '", serial number "' + serialNumber +
				'", and Tanium endpoint ID "' + taniumEndpointID + '".\n' +
				'Here\'s the response:\n' +
				JSON.stringify(patchStatusResponse, null, 2)
			);

			//Return false if no endpoints were found
			return false;
		}

		//Iterate page number in patch config
		this.patch_config.patch_status.page++;

		return patchStatusResponse;
	},

	/**
	 * Get the patch statuses for a single endpoint using the "Patch - Patch List Applicability
	 * Results" sensor.
	 *
	 * @param {String} [fqdn=] - The fully qualified domain name of the endpoint.
	 * @param {String} [serialNumber=] - The serial number of the endpoint.
	 * @param {String} [taniumEndpointID=] - The Tanium endpoint ID of the endpoint.
	 * If this is provided, the fqdn and serialNumber parameters will be ignored, as it is the most
	 *    authoritative way to identify an endpoint. If you have the Tanium endpoint ID, you can set
	 *    the other arguments to null (or whatever you like, as they'll be ignored).
	 * @returns {{data}}
	 * @private
	 */
	_getSingleEndpointPatchStatuses: function(fqdn, serialNumber, taniumEndpointID) {
		this._initPatchConfigIfEmpty();
		var patchStatusResponse;
		var gqUtil = new x_taniu_tan_core.GatewayQueryUtil();

		//Validate inputs
		if (!fqdn && !serialNumber && !taniumEndpointID) {
			throw new Error(
				'At least one of the following parameters must be provided when calling ' +
				'TaniumPatchUtil.getPatchStatusForEndpoint(): \n' +
				'fqdn, serialNumber, taniumEndpointID \n' +
				'(the first, second, and third parameters respectively).'
			);
		}

		gqUtil.useCachedData();

		//Limit to 1 result, since we only expect one endpoint to match the given criteria.
		//If more are returned, we don't want to risk a massive response and potential
		// performance issues, but we will detect an incorrect number of endpoints found and log a warning.
		gqUtil.setPageSize(1);

		//Filter by endpoint ID, serial number, and/or FQDN - whichever of those values are provided.
		//If none are provided, the query will return all endpoints, which is what we want when getting all patch statuses - but that's why this method is private. It's not meant to be called from outside of this class for that purpose, but should be called by other code that needs to get patch statuses for all endpoints.
		if (taniumEndpointID) {
			gqUtil.addFilter(
				'id',
				'EQ',
				taniumEndpointID.toString()
			);
		}
		if (fqdn) {
			gqUtil.addFilter(
				'name',
				'EQ',
				fqdn
			);
		}
		if (serialNumber) {
			gqUtil.addFilter(
				'serialNumber',
				'EQ',
				serialNumber
			);
		}

		gqUtil.addSensor('Computer Name');
		gqUtil.addSensor('Computer Serial Number');
		gqUtil.addSensor('OS Platform');

		gqUtil.addSensor('Patch - Patch List Applicability Results')
			.addColumn('Tanium UID')
			.addColumn('Install Status');

		patchStatusResponse = gqUtil.queryAsync(
			1,
			1,
			1,
			true,
			1,
			5,
			false
		);

		//Validate response. If no endpoints were found, throw an error.
		if (
			!patchStatusResponse ||
			!patchStatusResponse.hasOwnProperty('data') ||
			!patchStatusResponse.data ||
			!patchStatusResponse.data.hasOwnProperty('endpoints') ||
			!patchStatusResponse.data.endpoints ||
			!patchStatusResponse.data.endpoints.hasOwnProperty('edges') ||
			!patchStatusResponse.data.endpoints.edges ||
			patchStatusResponse.data.endpoints.edges.length < 1 ||
			!patchStatusResponse.data.endpoints.edges[0].hasOwnProperty('node') ||
			!patchStatusResponse.data.endpoints.edges[0].node
		) {
			gs.warn(
				'TaniumPatchUtil: No endpoints found when getting patch status for endpoint ' +
				'with FQDN "' + fqdn + '", serial number "' + serialNumber +
				'", and Tanium endpoint ID "' + taniumEndpointID + '".\n' +
				'Here\'s the response:\n' +
				JSON.stringify(patchStatusResponse, null, 2)
			);

			//Return false if no endpoints were found
			return false;
		}

		return patchStatusResponse;
	},

	_isLastPatchDefinitionPage: function(totalPatchDefinitionsCount) {
		var currentPage, pageSize, totalPageCount;

		this._initPatchConfigIfEmpty();

		currentPage = this.patch_config.patch_definitions.page;
		pageSize = this.patch_config.patch_definitions.page_size;
		totalPageCount = Math.ceil(totalPatchDefinitionsCount / pageSize);

		return currentPage >= totalPageCount;
	},

	_getPatchDefinitionsSkipValue: function() {
		var skipValue, currentPage, pageSize;

		this._initPatchConfigIfEmpty();

		currentPage = this.patch_config.patch_definitions.page;
		pageSize = this.patch_config.patch_definitions.page_size;

		/*
			skipValue (the number of patch definitions to skip when getting the next page) is calculated as follows:
			skipValue = (current page number * page size) - page size

			Examples:
			If the current page is 1 and the page size is 500, then the skip value is (1 * 500) - 500 = 0, so no patch definitions are skipped (which makes sense, since we're on the first page).

			If the current page is 3 and the page size is 500, then the skip value is (3 * 500) - 500 = 1000. This means that when we get the next page of patch definitions, we should skip the first 1000 patch definitions, and get the next 500 (from patch definitions index 1001 to 1500).
		*/
		skipValue = ((currentPage * pageSize) - pageSize);

		return skipValue;
	},

	/**
	 * Initialize the patch configuration if it is empty.
	 * @private
	 */
	_initPatchConfigIfEmpty: function() {
		//If patch config is already set (and is valid), just return it. Otherwise, initialize it.
		if (
			!gs.nil(this.patch_config) &&
			this.patch_config &&
			//Patch definition config
			this.patch_config.hasOwnProperty('patch_definitions') &&
			this.patch_config.patch_definitions.hasOwnProperty('page') &&
			this.patch_config.patch_definitions.hasOwnProperty('page_size') &&
			this.patch_config.patch_definitions.page >= 0 &&
			this.patch_config.patch_definitions.page_size >= 1 &&
			//Patch status config
			this.patch_config.hasOwnProperty('patch_status') &&
			this.patch_config.patch_status.hasOwnProperty('page') &&
			this.patch_config.patch_status.hasOwnProperty('page_size') &&
			this.patch_config.patch_status.page >= 0 &&
			this.patch_config.patch_status.page_size >= 1
		) {
			//If patch config is already set, just return it.
			// gs.debug('Patch config is already set. Returning it.');
			return this.patch_config;
		}

		// gs.debug('Patch config is not set. Initializing it.');
		if (this.patch_config) {
			gs.debug(
				'Patch config is set, but it is invalid. Re-initializing it.\n' +
				'Original:\n' + JSON.stringify(this.patch_config, null, 2)
			);
		}
		this.patch_config = {
			"patch_status": {
				"page": 0, //This one starts at 0 and is incremented when we step into the first page.
				"cursor": null,
				"page_size": parseInt(
					gs.getProperty(
						'x_taniu_tan_core.patch_status_page_size',
						'500'
					) || 500
				),
				"has_next_page": true
			},
			"patch_definitions": {
				"page": 1,
				"page_size": parseInt(
					gs.getProperty(
						'x_taniu_tan_core.patch_definitions_page_size',
						'500'
					) || 500
				),
				"has_next_page": true
			}
		};

		return this.patch_config;
	},

	type: 'TaniumPatchUtil'
});
